 1	import type { ReactNode } from 'react';
 2	
 3	import {
 4	  Button,
 5	  ButtonVariant,
 6	  Split,
 7	  SplitItem,
 8	  ToolbarItem,
 9	  Tooltip,
10	} from '@patternfly/react-core';
11	import { ColumnsIcon } from '@patternfly/react-icons';
12	import { useForkliftTranslation } from '@utils/i18n';
13	
14	type ManageColumnsToolbarItemProps = {
15	  children: ReactNode;
16	  /**
17	   * A handler for clicking the button.
18	   */
19	  showDialog: () => void;
20	  /**
21	   * A tooltip content.
22	   */
23	  tooltip?: string;
24	  /**
25	   * A text describing the button.
26	   */
27	  ariaLabel?: string;
28	};
29	
30	export const ManageColumnsToolbarItem = ({
31	  ariaLabel,
32	  children,
33	  showDialog,
34	  tooltip,
35	}: ManageColumnsToolbarItemProps) => {
36	  const { t } = useForkliftTranslation();
37	  const manageColumnsText = t('Manage columns');
38	  return (
39	    <ToolbarItem>
40	      <Tooltip content={tooltip ?? manageColumnsText}>
41	        <Button
42	          variant={ButtonVariant.plain}
43	          onClick={showDialog}
44	          aria-label={ariaLabel ?? manageColumnsText}
45	        >
46	          <Split hasGutter>
47	            <SplitItem>
48	              <ColumnsIcon />
49	            </SplitItem>
50	            <SplitItem>{manageColumnsText}</SplitItem>
51	          </Split>
52	        </Button>
53	      </Tooltip>
54	      {children}
55	    </ToolbarItem>
56	  );
57	};

